18	namespace serve {
19	
20	TVM_FFI_STATIC_INIT_BLOCK() { SamplerObj::RegisterReflection(); }
21	
22	/*!
23	 * \brief Sample a value from the input probability distribution with top-p.
24	 * The input is a batch of distributions, and we use `unit_offset` to specify
25	 * which distribution to sample from.
26	 * \param prob The input batch of probability distributions.
27	 * \param unit_offset The offset specifying which distribution to output
28	 * \param input_prob_offset The offset specifying which distribution to sample from.
29	 * \param top_p The top-p value of sampling.
30	 * \param uniform_sample The random number in [0, 1] for sampling.
31	 * \return The sampled value and probability.
32	 * \note This function is an enhancement of SampleTopPFromProb in TVM Unity.
33	 * We will upstream the enhancement after it gets stable.
34	 */
35	TokenProbPair SampleTopPFromProb(Tensor prob, int unit_offset, int input_prob_offset, double top_p,
36	                                 double uniform_sample) {
37	  // prob: (*, v)
38	  // The prob array may have arbitrary ndim and shape.
39	  // The last dimension corresponds to the prob distribution size.
40	  // We use the `unit_offset` parameter to determine which slice
41	  // of the prob array we sample from.
42	
43	  TVM_FFI_ICHECK(prob.IsContiguous());
44	  TVM_FFI_ICHECK(prob.DataType() == (DLDataType{kDLFloat, 32, 1}));
45	  TVM_FFI_ICHECK_EQ(prob->device.device_type, DLDeviceType::kDLCPU);
46	
47	  int64_t ndata = prob->shape[prob->ndim - 1];
48	  const float* __restrict p_prob =
49	      static_cast<float*>(__builtin_assume_aligned(prob->data, 4)) + (input_prob_offset * ndata);
50	  constexpr double one = 1.0f - 1e-5f;
51	
52	  if (top_p == 0) {
53	    // Specially handle case where top_p == 0.
54	    // This case is equivalent to doing argmax.
55	    int argmax_pos = -1;
56	    float max_prob = 0.0;
57	    float sum_prob = 0.0;
58	    for (int i = 0; i < ndata; ++i) {
59	      if (p_prob[i] > max_prob) {
60	        max_prob = p_prob[i];
61	        argmax_pos = i;
62	      }
63	      // Early exit.
64	      sum_prob += p_prob[i];
65	      if (1 - sum_prob <= max_prob) {
66	        break;
67	      }
68	    }
69	    return {argmax_pos, 1.0};
70	  }
71	
72	  if (top_p >= one) {
73	    // Specially handle case where top_p == 1.
74	    double prob_sum = 0.0f;
75	    for (int64_t i = 0; i < ndata; ++i) {
76	      prob_sum += p_prob[i];
77	      if (prob_sum >= uniform_sample) {
78	        return {i, p_prob[i]};
79	      }
80	    }
81	    TVM_FFI_ICHECK(false) << "Possibly prob distribution contains NAN.";
82	  }
83	
84	  // Key observation: when we are doing top_p sampling
85	  // usually we only need to preserve some of the elements with
86	  // high probabilities before we do sort
87	  thread_local std::vector<std::pair<float, int>> data;
88	
89	  auto sample_top_p_with_filter = [&](float cuttoff) -> std::pair<float, int64_t> {
90	    data.clear();
91	    // filter the data with cuttoff
92	    float cutoff_sum = 0.0f;
93	    for (int64_t i = 0; i < ndata; ++i) {
94	      if (p_prob[i] >= cuttoff) {
95	        cutoff_sum += p_prob[i];
96	        data.emplace_back(std::make_pair(p_prob[i], static_cast<int>(i)));
97	        if (cutoff_sum > 1 - cuttoff) {
98	          // Short cut. When the remaining parts cannot have total
99	          // probability larger than cutoff, we can quit.
100	          break;
101	        }
102	      }
103	    }
104	    if (data.size() == 0) return std::make_pair(-1, -1);
105	    auto fcmp = [](const std::pair<float, int>& lhs, const std::pair<float, int>& rhs) {
106	      return lhs.first > rhs.first;
107	    };
108	    std::sort(data.begin(), data.end(), fcmp);
109	
110	    // short cut, if we know that
111	    // uniform sample < p[0] / top_p
112	    // we know that unform_sample < p[0] / top_p_sum
113	    // because top_p_sum guarantees to be smaller than top_p
114	    // so we can simply return the argmax sample
115	    // without computing anything
116	    if (uniform_sample < data[0].first / top_p) {
117	      return std::make_pair(data[0].first, data[0].second);
118	    }
119	
120	    // compute top_p_sum
121	    float cum_sum_prob = 0.0f;
122	    float top_p_sum = 0.0f;
123	    for (auto it = data.begin(); it != data.end(); ++it) {
124	      float prob = it->first;
125	      if (cum_sum_prob < top_p) {
126	        top_p_sum += prob;
127	      } else {
128	        // we get to the right cutoff pt
129	        break;
130	      }
131	      cum_sum_prob += prob;
132	      it->first = cum_sum_prob;
133	    }
134	    // we find that the current total sum by the given cutoff
135	    // is not sufficient to cover everything
136	    // this means we might need to retry a smaller cutoff pt.
137	    if (cum_sum_prob < top_p && cuttoff != 0.0f) return std::make_pair(-1, -1);
138	
139	    float last_cum_sum_prob = 0.0;
140	    for (auto it = data.begin(); it != data.end(); ++it) {
141	      if (uniform_sample < it->first / top_p_sum) {
142	        return std::make_pair(it->first - last_cum_sum_prob, it->second);
143	      }
144	      last_cum_sum_prob = it->first;
145	    }
146	    return std::make_pair(data[static_cast<int64_t>(data.size()) - 1].first - last_cum_sum_prob,
147	                          data[static_cast<int64_t>(data.size()) - 1].second);
148	  };
149	
150	  if (top_p < 1) {
151	    // sample through cutoff by a number
152	    // by pigeonhole principle we will get at most 1024 elements
153	    // usually it is much less by applying this filtering(order of 10 - 20)
154	    data.reserve(256);
155	    std::pair<float, int64_t> sampled_index = sample_top_p_with_filter(top_p / 1024);
156	    if (sampled_index.second >= 0) return {sampled_index.second, sampled_index.first};
157	  }
158	  // fallback via full prob, rare case
159	  data.reserve(ndata);
160	  std::pair<float, int64_t> sampled_index = sample_top_p_with_filter(0.0f);
161	  TVM_FFI_ICHECK_GE(sampled_index.second, 0);
162	  return {sampled_index.second, sampled_index.first};
163	}
164	
165	/*!
166	 * \brief Renormalize the probability distribution by the top p value.
167	 * \param prob The input batch of probability distributions.
168	 * \param unit_offset The offset specifying which distribution to output
169	 * \param top_p The top p value for renormalization.
170	 * \param eps A small epsilon value for comparison stability.
171	 */
172	void RenormalizeProbByTopP(Tensor prob, int unit_offset, double top_p, double eps) {
173	  // prob: (*, v)
174	  // The prob array may have arbitrary ndim and shape.
175	  // The last dimension corresponds to the prob distribution size.
176	  // We use the `unit_offset` parameter to determine which slice
177	  // of the prob array we will renormalize.
178	  TVM_FFI_ICHECK(prob.IsContiguous());
179	  TVM_FFI_ICHECK(prob.DataType() == (DLDataType{kDLFloat, 32, 1}));
180	  TVM_FFI_ICHECK_EQ(prob->device.device_type, DLDeviceType::kDLCPU);
181	
182	  if (top_p == 1.0) {
183	    // No renormalization is needed if top_p is 1.
184	    return;
185	  }
186	
187	  int vocab_size = prob->shape[prob->ndim - 1];
188	  float* __restrict p_prob =
189	      static_cast<float*>(__builtin_assume_aligned(prob->data, 4)) + (unit_offset * vocab_size);
190	
191	  // We manually choice the cutoff values of "top_p / 256" and "top_p / 8192".
192	  // In most of the cases, only one round is needed.
193	  std::vector<double> cutoff_values{top_p / 256, top_p / 8192, 0.0f};
194	
195	  // Create the upper partition vector and the lower partition rolling vectors.
196	  std::vector<float> upper_partition;
197	  std::vector<float> lower_partitions[2];
198	  upper_partition.reserve(vocab_size);
199	  lower_partitions[0].reserve(vocab_size);
200	  lower_partitions[1].reserve(vocab_size);
201	  float upper_partition_sum = 0.0;
202	  for (int round = 0; round < static_cast<int>(cutoff_values.size()); ++round) {
203	    const float* lower_partition_begin;
204	    const float* lower_partition_end;
205	    if (round == 0) {
206	      lower_partition_begin = p_prob;
207	      lower_partition_end = p_prob + vocab_size;
208	    } else {
209	      int idx = (round - 1) & 1;
210	      lower_partition_begin = lower_partitions[idx].data();
211	      lower_partition_end = lower_partitions[idx].data() + lower_partitions[idx].size();
212	    }
213	
214	    // - Partition the last round lower partition into upper and lower
215	    // based on the new cutoff value.
216	    std::vector<float>& lower_partition = lower_partitions[round & 1];
217	    lower_partition.clear();
218	    for (const float* ptr = lower_partition_begin; ptr != lower_partition_end; ++ptr) {
219	      if (*ptr >= cutoff_values[round]) {
220	        upper_partition.push_back(*ptr);
221	        upper_partition_sum += *ptr;
222	      } else {
223	        lower_partition.push_back(*ptr);
224	      }
225	    }
226	    // - If the upper partition sum is at least top p, exit the loop.
227	    if (upper_partition_sum >= top_p - eps) {
228	      break;
229	    }
230	  }
231	
232	  // - Sort the upper partition in descending order.
233	  std::sort(upper_partition.begin(), upper_partition.end(), std::greater<>());
234	  // - Find the top p boundary prob value.
235	  float boundary_value = -1.0;
236	  upper_partition_sum = 0.0;
237	  for (float upper_value : upper_partition) {
238	    upper_partition_sum += upper_value;
239	    if (upper_partition_sum >= top_p - eps) {
240	      boundary_value = upper_value;
241	      break;
242	    }
243	  }
244	  // - Mask all values smaller than the boundary to 0.
245	  float renormalize_sum = 0.0;
246	  std::vector<int> upper_partition_indices;
247	  upper_partition_indices.reserve(vocab_size);
248	  for (int i = 0; i < vocab_size; ++i) {
249	    if (p_prob[i] >= boundary_value) {
250	      upper_partition_indices.push_back(i);
251	      renormalize_sum += p_prob[i];
252	    } else {
253	      p_prob[i] = 0.0;
254	    }
255	  }
256	  // - Renormalize.
257	  for (int idx : upper_partition_indices) {
258	    p_prob[idx] /= renormalize_sum;
259	  }
260	}
261	
262	namespace detail {
263	
264	/*! \brief Implementation of getting top probs on CPU. */
265	template <int num_top_probs>
266	std::vector<TokenProbPair> ComputeTopProbsImpl(const float* p_prob, int ndata) {
267	  std::vector<TokenProbPair> top_probs;
268	  top_probs.reserve(num_top_probs);
269	  for (int i = 0; i < num_top_probs; ++i) {
270	    top_probs.emplace_back(-1, -1.0f);
271	  }
272	
273	  float sum_prob = 0.0;
274	  // Selection argsort.
275	  for (int p = 0; p < ndata; ++p) {
276	    int i = num_top_probs - 1;
277	    for (; i >= 0; --i) {
278	      if (p_prob[p] > top_probs[i].second) {
279	        if (i != num_top_probs - 1) {
280	          top_probs[i + 1] = top_probs[i];
281	        }
282	      } else {
283	        break;
284	      }
285	    }
286	    if (i != num_top_probs - 1) {
287	      top_probs[i + 1] = {p, p_prob[p]};
288	    }
289	
290	    // Early exit.
291	    sum_prob += p_prob[p];
292	    if (1 - sum_prob <= top_probs[num_top_probs - 1].second) {
293	      break;
294	    }
295	  }
296	  return top_probs;
297	}
298	
299	}  // namespace detail
300	
301	/*! \brief Get the probs of a few number of tokens with top probabilities. */
302	inline std::vector<TokenProbPair> ComputeTopProbs(Tensor prob, int unit_offset, int num_top_probs) {
303	  TVM_FFI_ICHECK_LE(num_top_probs, 5);
304	  TVM_FFI_ICHECK_EQ(prob->ndim, 2);
305	  int ndata = prob->shape[1];
306	  const float* __restrict p_prob =
307	      static_cast<float*>(__builtin_assume_aligned(prob->data, 4)) + (unit_offset * ndata);
308	  switch (num_top_probs) {
309	    case 0:
310	      return {};
311	    case 1:
312	      return detail::ComputeTopProbsImpl<1>(p_prob, ndata);
313	    case 2:
314	      return detail::ComputeTopProbsImpl<2>(p_prob, ndata);
315	    case 3:
316	      return detail::ComputeTopProbsImpl<3>(p_prob, ndata);
317	    case 4:
318	      return detail::ComputeTopProbsImpl<4>(p_prob, ndata);
319	    case 5:
320	      return detail::ComputeTopProbsImpl<5>(p_prob, ndata);
321	  }
322	  throw;
323	}
324	
325	/********************* CPU Sampler *********************/
326	
327	class CPUSampler : public SamplerObj {
328	 public:
329	  explicit CPUSampler(Optional<EventTraceRecorder> trace_recorder)
330	      : trace_recorder_(std::move(trace_recorder)) {}
331	
332	  Tensor BatchRenormalizeProbsByTopP(Tensor probs_on_device,                  //
333	                                     const std::vector<int>& sample_indices,  //
334	                                     const Array<String>& request_ids,        //
335	                                     const Array<GenerationConfig>& generation_cfg) final {
336	    // probs_on_device: (n, v)
337	    TVM_FFI_ICHECK_EQ(probs_on_device->ndim, 2);
338	    // - Copy probs to CPU
339	    RECORD_EVENT(trace_recorder_, request_ids, "start copy probs to CPU");
340	    Tensor probs_on_host = CopyProbsToCPU(probs_on_device);
341	    RECORD_EVENT(trace_recorder_, request_ids, "finish copy probs to CPU");
342	    int num_samples = sample_indices.size();
343	    int num_probs = probs_on_device->shape[0];
344	    int vocab_size = probs_on_device->shape[1];
345	    TVM_FFI_ICHECK_EQ(request_ids.size(), num_samples);
346	    TVM_FFI_ICHECK_EQ(generation_cfg.size(), num_samples);
347	
348	    std::vector<int> top_p_indices;
349	    std::vector<double> top_p_values;
350	    for (int i = 0; i < num_samples; ++i) {
351	      if (top_p_indices.empty() || top_p_indices.back() != sample_indices[i]) {
352	        top_p_indices.push_back(sample_indices[i]);
353	        top_p_values.push_back(generation_cfg[i]->top_p);
354	      } else {
355	        TVM_FFI_ICHECK(fabs(top_p_values.back() - generation_cfg[i]->top_p) < eps_)
356	            << "Sampler requires the top_p values for each prob distribution are the same.";
357	      }
358	    }
359	    if (top_p_indices.empty()) {
360	      // Return if no top p needs to apply.
361	      return probs_on_host;
362	    }
363	
364	    tvm::runtime::parallel_for_with_threading_backend(
365	        [this, &probs_on_host, &request_ids, &top_p_indices, &top_p_values](int i) {
366	          RECORD_EVENT(this->trace_recorder_, request_ids[i], "start renormalize by top p");
367	          RenormalizeProbByTopP(probs_on_host, top_p_indices[i], top_p_values[i], eps_);
368	          RECORD_EVENT(this->trace_recorder_, request_ids[i], "finish renormalize by top p");
369	        },
370	        0, static_cast<int64_t>(top_p_indices.size()));
371	
372	    return probs_on_host;
373	  }
374	
375	  std::vector<SampleResult> BatchSampleTokensWithProbBeforeTopP(
376	      Tensor probs_on_device,                         //
377	      const std::vector<int>& sample_indices,         //
378	      const Array<String>& request_ids,               //
379	      const Array<GenerationConfig>& generation_cfg,  //
380	      const std::vector<RandomGenerator*>& rngs) final {
381	    // probs_on_device: (n, v)
382	    TVM_FFI_ICHECK_EQ(probs_on_device->ndim, 2);
383	    // - Copy probs to CPU
384	    RECORD_EVENT(trace_recorder_, request_ids, "start copy probs to CPU");
385	    Tensor probs_on_host = CopyProbsToCPU(probs_on_device);
386	    RECORD_EVENT(trace_recorder_, request_ids, "finish copy probs to CPU");
387	
388	    return BatchSampleTokensImpl(probs_on_host, sample_indices, request_ids, generation_cfg, rngs,
389	                                 /*top_p_applied=*/false);
390	  }
391	
392	  std::vector<SampleResult> BatchSampleTokensWithProbAfterTopP(
393	      Tensor probs_on_host,                           //
394	      const std::vector<int>& sample_indices,         //
395	      const Array<String>& request_ids,               //
396	      const Array<GenerationConfig>& generation_cfg,  //
397	      const std::vector<RandomGenerator*>& rngs) final {
398	    return BatchSampleTokensImpl(probs_on_host, sample_indices, request_ids, generation_cfg, rngs,
399	                                 /*top_p_applied=*/true);
400	  }
401	
402	  std::pair<std::vector<std::vector<SampleResult>>, std::vector<int>>
403	  BatchVerifyDraftTokensWithProbAfterTopP(
404	      Tensor probs_on_host, const Array<String>& request_ids,
405	      const std::vector<int>& cum_verify_lengths, const Array<GenerationConfig>& generation_cfg,
406	      const std::vector<RandomGenerator*>& rngs,
407	      const std::vector<std::vector<SampleResult>>& draft_output_tokens,
408	      const std::vector<int64_t>& token_tree_parent_ptr, Tensor draft_probs_on_device) final {
409	    // probs_on_host: (n, v)
410	    RECORD_EVENT(trace_recorder_, request_ids, "start draft verification");
411	    TVM_FFI_ICHECK_EQ(probs_on_host->ndim, 2);
412	
413	    int num_sequence = static_cast<int>(cum_verify_lengths.size()) - 1;
414	    TVM_FFI_ICHECK_EQ(rngs.size(), num_sequence);
415	    TVM_FFI_ICHECK_EQ(draft_output_tokens.size(), num_sequence);
416	
417	    Tensor draft_probs_on_host = draft_probs_on_device.CopyTo(DLDevice{kDLCPU, 0});
418	    std::vector<std::vector<SampleResult>> sample_results;
419	    sample_results.resize(num_sequence);
420	
421	    float* __restrict global_p_probs =
422	        static_cast<float*>(__builtin_assume_aligned(probs_on_host->data, 4));
423	    int vocab_size = probs_on_host->shape[1];
424	
425	    std::vector<int> last_accepted_tree_node(num_sequence, 0);
426	    tvm::runtime::parallel_for_with_threading_backend(
427	        [&](int i) {
428	          int verify_start = cum_verify_lengths[i];
429	          int verify_end = cum_verify_lengths[i + 1];
430	
431	          TVM_FFI_ICHECK_EQ(token_tree_parent_ptr[verify_start], -1);
432	          for (int j = verify_start + 1; j < verify_end; ++j) {
433	            TVM_FFI_ICHECK_EQ(token_tree_parent_ptr[j], j - verify_start - 1)
434	                << "CPU sampler only supports chain-style draft tokens.";
435	          }
436	
437	          int cur_token_idx = 0;
438	          // Sub 1 to ignore the last prediction.
439	          for (; cur_token_idx < verify_end - verify_start - 1; ++cur_token_idx) {
440	            float* p_probs = global_p_probs + (verify_start + cur_token_idx) * vocab_size;
441	            int cur_token = draft_output_tokens[i][cur_token_idx].GetTokenId();
442	            float q_value = draft_output_tokens[i][cur_token_idx].sampled_token_id.second;
443	            float p_value = p_probs[cur_token];
444	
445	            if (p_value >= q_value) {
446	              sample_results[i].push_back(
447	                  SampleResult{{cur_token, p_value},
448	                               ComputeTopProbs(probs_on_host, verify_start + cur_token_idx,
449	                                               generation_cfg[i]->top_logprobs)});
450	              continue;
451	            }
452	            float r = rngs[i]->GetRandomNumber();
453	            if (r < p_value / (q_value + eps_)) {
454	              sample_results[i].push_back(
455	                  SampleResult{{cur_token, p_value},
456	                               ComputeTopProbs(probs_on_host, verify_start + cur_token_idx,
457	                                               generation_cfg[i]->top_logprobs)});
458	              continue;
459	            }
460	
461	            // normalize a new probability distribution
462	            double sum_v = 0.0;
463	            const float* __restrict p_qdist =
464	                static_cast<float*>(__builtin_assume_aligned(draft_probs_on_host->data, 4)) +
465	                (verify_start + cur_token_idx + 1) * vocab_size;
466	
467	            for (int j = 0; j < vocab_size; ++j) {
468	              p_probs[j] = std::max(p_probs[j] - p_qdist[j], 0.0f);
469	              sum_v += p_probs[j];
470	            }
471	            for (int j = 0; j < vocab_size; ++j) {
472	              p_probs[j] /= sum_v;
473	            }
474	
475	            // sample a new token from the new distribution
476	            SampleResult sample_result;
477	            sample_result.sampled_token_id = SampleTopPFromProb(
478	                probs_on_host, verify_start + cur_token_idx, verify_start + cur_token_idx,
479	                /*top_p=*/1.0f, rngs[i]->GetRandomNumber());
480	            sample_result.top_prob_tokens = ComputeTopProbs(
481	                probs_on_host, verify_start + cur_token_idx, generation_cfg[i]->top_logprobs);
482	            sample_results[i].push_back(sample_result);
483	            break;
484	          }
485	          last_accepted_tree_node[i] = cur_token_idx;
486	          // if cur_token_idx == verify_end - verify_start - 1
487	          // all draft tokens are accepted
488	          // we sample a new token
489	          if (cur_token_idx == verify_end - verify_start - 1) {
490	            SampleResult sample_result;
491	            // sample a new token from the original distribution
492	            sample_result.sampled_token_id = SampleTopPFromProb(
493	                probs_on_host, verify_start + cur_token_idx, verify_start + cur_token_idx,
494	                /*top_p=*/1.0f, rngs[i]->GetRandomNumber());
495	            sample_result.top_prob_tokens = ComputeTopProbs(
496	                probs_on_host, verify_start + cur_token_idx, generation_cfg[i]->top_logprobs);
497	            sample_results[i].push_back(sample_result);
498	          }
499	        },
500	        0, num_sequence);
501	    RECORD_EVENT(trace_recorder_, request_ids, "finish draft verification");
502	    return {sample_results, last_accepted_tree_node};
503	  }
504	
505	 private:
506	  std::vector<SampleResult> BatchSampleTokensImpl(Tensor probs_on_host,                           //
507	                                                  const std::vector<int>& sample_indices,         //
508	                                                  const Array<String>& request_ids,               //
509	                                                  const Array<GenerationConfig>& generation_cfg,  //
510	                                                  const std::vector<RandomGenerator*>& rngs,      //
511	                                                  bool top_p_applied) {
512	    // probs_on_host: (n, v)
513	    RECORD_EVENT(trace_recorder_, request_ids, "start sampling");
514	    TVM_FFI_ICHECK_EQ(probs_on_host->ndim, 2);
515	    TVM_FFI_ICHECK_EQ(probs_on_host->device.device_type, DLDeviceType::kDLCPU);
516	
517	    // - Sample tokens from probabilities.
518	    int n = request_ids.size();
519	    TVM_FFI_ICHECK_EQ(generation_cfg.size(), n);
520	    TVM_FFI_ICHECK_EQ(rngs.size(), n);
521	
522	    std::vector<SampleResult> sample_results;
523	    sample_results.resize(n);
524	
525	    tvm::runtime::parallel_for_with_threading_backend(
526	        [this, &sample_results, &probs_on_host, &generation_cfg, &rngs, &request_ids, top_p_applied,
527	         sample_indices](int i) {
528	          RECORD_EVENT(this->trace_recorder_, request_ids[i], "start sample token");
529	          // Sample top p from probability.
530	          double top_p =
531	              top_p_applied
532	                  ? 1.0f
533	                  : (generation_cfg[i]->temperature < eps_ ? 0.0 : generation_cfg[i]->top_p);
534	          sample_results[i].sampled_token_id = SampleTopPFromProb(
535	              probs_on_host, i, sample_indices[i], top_p, rngs[i]->GetRandomNumber());
536	          sample_results[i].top_prob_tokens =
537	              ComputeTopProbs(probs_on_host, i, generation_cfg[i]->top_logprobs);
538	          RECORD_EVENT(this->trace_recorder_, request_ids[i], "finish sample token");
539	        },
540	        0, n);
541	    RECORD_EVENT(trace_recorder_, request_ids, "finish sampling");
542	    return sample_results;
543	  }
544	
545	  /*! \brief Copy prob distributions from device to CPU. */
546	  Tensor CopyProbsToCPU(Tensor probs_on_device) {
547	    // probs_on_device: (n, v)
548	    if (probs_on_device->device.device_type == kDLCPU) {
549	      return probs_on_device;
550	    }
551	
552	    TVM_FFI_ICHECK(probs_on_device->device.device_type != kDLCPU);
553	    if (probs_host_.defined()) {
554	      TVM_FFI_ICHECK_EQ(probs_host_->shape[1], probs_on_device->shape[1]);
555	    }
556	
557	    int64_t init_size = probs_host_.defined() ? probs_host_->shape[0] : 32;
558	    int64_t num_tokens = probs_on_device->shape[0];
559	    int64_t vocab_size = probs_on_device->shape[1];
560	    while (init_size < num_tokens) {
561	      init_size *= 2;
562	    }
563	    if (!probs_host_.defined() || init_size != probs_host_->shape[0]) {
564	      probs_host_ =
565	          Tensor::Empty({init_size, vocab_size}, probs_on_device->dtype, DLDevice{kDLCPU, 0});
566	    }
567	    TVM_FFI_ICHECK_LE(num_tokens, probs_host_->shape[0]);
568	    Tensor view = probs_host_.CreateView({num_tokens, vocab_size}, probs_on_device->dtype);
569	    view.CopyFrom(probs_on_device);
570	    return view;
571	  }
572	
573	  /*! \brief The event trace recorder for requests. */
574	  Optional<EventTraceRecorder> trace_recorder_;
575	  /*! \brief Customized function which computes prob distribution from logits */
576	  Function flogits_to_probs_inplace_;
577	  /*! \brief Probability distribution array on CPU. */
578	  Tensor probs_host_{nullptr};
579	  const float eps_ = 1e-5;
580	};
581	
582	Sampler Sampler::CreateCPUSampler(Optional<EventTraceRecorder> trace_recorder) {
583	  return Sampler(tvm::ffi::make_object<CPUSampler>(std::move(trace_recorder)));
584	}
585	
586	}  // namespace serve
587	}  // namespace llm
588	}  // namespace mlc
