20	inline bool FlashInferSamplingAvailable(Device device) {
21	  // Device must be CUDA, and FlashInfer must be enabled.
22	  if (device.device_type != DLDeviceType::kDLCUDA ||
23	      !Function::GetGlobal("flashinfer.sampling.parallel_sampling_from_prob").has_value()) {
24	    return false;
25	  }
26	  // Compute version must be at least 8.0
27	  Any rv;
28	  DeviceAPI::Get(device)->GetAttr(device, kComputeVersion, &rv);
29	  std::string compute_version = rv.cast<std::string>();
30	  std::string major_version = compute_version.substr(0, compute_version.find('.'));
31	  return std::stoi(major_version) >= 8;
32	}
