34	inline void CopyArray(Tensor src, Tensor dst, TVMStreamHandle copy_stream) {
35	  DLTensor dl_dst = *(dst.operator->());
36	  Tensor::CopyFromTo(src.operator->(), &dl_dst, copy_stream);
37	}
