39	inline void SyncCopyStream(Device device, TVMStreamHandle compute_stream,
40	                           TVMStreamHandle copy_stream) {
41	  // - If there is no particular copy stream, no action is needed.
42	  if (copy_stream == nullptr) {
43	    return;
44	  }
45	  // - Sync two streams.
46	  DeviceAPI::Get(device)->SyncStreamFromTo(device, copy_stream, compute_stream);
47	}
