52	 public:
53	  explicit GPUSampler(int max_num_sample, int vocab_size, FunctionTable* ft, DLDevice device,
54	                      Optional<EventTraceRecorder> trace_recorder)
55	      : max_num_sample_(max_num_sample),
56	        vocab_size_(vocab_size),
57	        flashinfer_sampling_available_(FlashInferSamplingAvailable(device)),
58	        device_(device),
59	        gpu_multinomial_from_uniform_func_(ft->gpu_multinomial_from_uniform_func_),
60	        gpu_argsort_probs_func_(ft->gpu_argsort_probs_func_),
61	        gpu_sample_with_top_p_func_(ft->gpu_sample_with_top_p_func_),
62	        gpu_sampler_take_probs_func_(ft->gpu_sampler_take_probs_func_),
63	        gpu_verify_draft_tokens_func_(ft->gpu_verify_draft_tokens_func_),
64	        gpu_renormalize_by_top_p_func_(ft->gpu_renormalize_by_top_p_func_),
65	        trace_recorder_(std::move(trace_recorder)) {
66	    TVM_FFI_ICHECK(gpu_multinomial_from_uniform_func_.defined());
67	    TVM_FFI_ICHECK(gpu_argsort_probs_func_.defined());
68	    TVM_FFI_ICHECK(gpu_sample_with_top_p_func_.defined());
69	    TVM_FFI_ICHECK(gpu_sampler_take_probs_func_.defined());
70	
71	    flashinfer_multinomial_sample_func_ =
72	        Function::GetGlobal("flashinfer.sampling.parallel_sampling_from_prob");
73	
74	    Device preferred_host_device = GetPreferredHostDevice(device);
75	    // We support at most 5 top prob results for each sequence.
76	    // Initialize auxiliary arrays on CPU.
77	    uniform_samples_host_ = Tensor::Empty({max_num_sample}, dtype_f32_, preferred_host_device);
78	    sample_indices_host_ = Tensor::Empty({max_num_sample}, dtype_i32_, preferred_host_device);
79	    top_p_host_ = Tensor::Empty({max_num_sample}, dtype_f32_, preferred_host_device);
80	    top_p_init_pivots_host_ = Tensor::Empty({max_num_sample, num_top_p_cutoff_pivots_}, dtype_f32_,
81	                                            preferred_host_device);
82	    top_prob_offsets_host_ = Tensor::Empty({max_num_sample * 5}, dtype_i32_, preferred_host_device);
83	    draft_tokens_host_ = Tensor::Empty({max_num_sample}, dtype_i32_, preferred_host_device);
84	    token_tree_first_child_host_ =
