91	    sampled_probs_host_ = Tensor::Empty({max_num_sample}, dtype_f32_, preferred_host_device);
92	    top_prob_probs_host_ = Tensor::Empty({max_num_sample * 5}, dtype_f32_, preferred_host_device);
93	    top_prob_indices_host_ = Tensor::Empty({max_num_sample * 5}, dtype_i32_, preferred_host_device);
94	    // Initialize auxiliary arrays on GPU.
95	    uniform_samples_device_ = Tensor::Empty({max_num_sample}, dtype_f32_, device);
96	    sample_indices_device_ = Tensor::Empty({max_num_sample}, dtype_i32_, device);
97	    top_p_device_ = Tensor::Empty({max_num_sample}, dtype_f32_, device);
98	    top_p_init_pivots_device_ =
99	        Tensor::Empty({max_num_sample, num_top_p_cutoff_pivots_}, dtype_f32_, device);
100	    top_prob_offsets_device_ = Tensor::Empty({max_num_sample * 5}, dtype_i32_, device);
101	    draft_tokens_device_ = Tensor::Empty({max_num_sample}, dtype_i32_, device);
102	    token_tree_first_child_device_ = Tensor::Empty({max_num_sample}, dtype_i32_, device);
103	    token_tree_next_sibling_device_ = Tensor::Empty({max_num_sample}, dtype_i32_, device);
104	    token_tree_parent_ptr_device_ = Tensor::Empty({max_num_sample}, dtype_i32_, device);
