124	  Tensor BatchRenormalizeProbsByTopP(Tensor probs_on_device,                  //
125	                                     const std::vector<int>& sample_indices,  //
126	                                     const Array<String>& request_ids,        //
127	                                     const Array<GenerationConfig>& generation_cfg) final {
128	    NVTXScopedRange nvtx_scope("BatchRenormalizeProbsByTopP");
129	    // probs_on_device: (n, v)
130	    RECORD_EVENT(trace_recorder_, request_ids, "start renormalization by top p");
131	    TVM_FFI_ICHECK_EQ(probs_on_device->ndim, 2);
132	    int num_samples = sample_indices.size();
133	    int num_probs = probs_on_device->shape[0];
134	    int vocab_size = probs_on_device->shape[1];
135	    TVM_FFI_ICHECK_LE(num_probs, max_num_sample_);
136	    TVM_FFI_ICHECK_EQ(generation_cfg.size(), num_samples);
137	
138	    // - Check if there is need for applying top p.
139	    bool need_top_p = CheckTopP(generation_cfg, sample_indices, num_probs, num_samples, vocab_size);
140	    if (!need_top_p) {
141	      return probs_on_device;
142	    }
143	
144	    // - Copy auxiliary array for top-p and initial pivots.
145	    Tensor top_p_host = top_p_host_.CreateView({num_probs}, dtype_f32_);
146	    Tensor top_p_device = top_p_device_.CreateView({num_probs}, dtype_f32_);
147	    CopyArray(/*src=*/top_p_host, /*dst=*/top_p_device, copy_stream_);
148	
149	    Tensor top_p_init_pivots_host =
150	        top_p_init_pivots_host_.CreateView({num_probs, num_top_p_cutoff_pivots_}, dtype_f32_);
151	    Tensor top_p_init_pivots_device =
152	        top_p_init_pivots_device_.CreateView({num_probs, num_top_p_cutoff_pivots_}, dtype_f32_);
153	    const float* p_top_p = static_cast<const float*>(top_p_host->data);
154	    float* p_top_p_init_pivots = static_cast<float*>(top_p_init_pivots_host->data);
155	    for (int i = 0; i < num_probs; ++i) {
156	      if (1 - p_top_p[i] >= 0.02) {
157	        p_top_p_init_pivots[i * num_top_p_cutoff_pivots_] =
158	            std::min(1 - p_top_p[i], static_cast<float>(0.5));
159	        p_top_p_init_pivots[i * num_top_p_cutoff_pivots_ + 1] = 0.02;
160	        p_top_p_init_pivots[i * num_top_p_cutoff_pivots_ + 2] = 0.01;
161	      } else {
162	        p_top_p_init_pivots[i * num_top_p_cutoff_pivots_] = 1 - p_top_p[i];
163	        p_top_p_init_pivots[i * num_top_p_cutoff_pivots_ + 1] = (1 - p_top_p[i]) / 2;
164	        p_top_p_init_pivots[i * num_top_p_cutoff_pivots_ + 2] = (1 - p_top_p[i]) / 4;
165	      }
166	    }
167	    CopyArray(/*src=*/top_p_init_pivots_host, /*dst=*/top_p_init_pivots_device, copy_stream_);
168	    SyncCopyStream(device_, compute_stream_, copy_stream_);
169	
170	    // - Renormalize the prob with top p.
171	    Tensor renormed_probs_on_device =
172	        gpu_renormalize_by_top_p_func_(probs_on_device, top_p_device, top_p_init_pivots_device)
173	            .cast<Tensor>();
174	
175	    RECORD_EVENT(trace_recorder_, request_ids, "finish renormalization by top p");
176	    return renormed_probs_on_device;
177	  }
