201	  std::pair<std::vector<std::vector<SampleResult>>, std::vector<int>>
202	  BatchVerifyDraftTokensWithProbAfterTopP(
203	      Tensor probs_on_device, const Array<String>& request_ids,
204	      const std::vector<int>& cum_verify_lengths, const Array<GenerationConfig>& generation_cfg,
205	      const std::vector<RandomGenerator*>& rngs,
206	      const std::vector<std::vector<SampleResult>>& draft_output_tokens,
207	      const std::vector<int64_t>& token_tree_parent_ptr, Tensor draft_probs_on_device) final {
208	    NVTXScopedRange nvtx_scope("BatchVerifyDraftTokensWithProbAfterTopP");
209	    std::vector<std::vector<SampleResult>> sample_results;
210	    // probs_on_device: (n, v)
211	    RECORD_EVENT(trace_recorder_, request_ids, "start draft verification");
212	    TVM_FFI_ICHECK_EQ(probs_on_device->ndim, 2);
213	
214	    int num_sequence = static_cast<int>(cum_verify_lengths.size()) - 1;
215	    TVM_FFI_ICHECK_EQ(rngs.size(), num_sequence);
216	    TVM_FFI_ICHECK_EQ(draft_output_tokens.size(), num_sequence);
217	    sample_results.resize(num_sequence);
218	
219	    int num_nodes = cum_verify_lengths.back();
220	    TVM_FFI_ICHECK(num_nodes <= max_num_sample_);
221	    TVM_FFI_ICHECK_EQ(draft_probs_on_device->shape[0], num_nodes);
222	    Tensor uniform_samples_device = GenerateUniformSamples(rngs, cum_verify_lengths);
223	    Tensor draft_tokens_host = draft_tokens_host_.CreateView({num_nodes}, dtype_i32_);
224	    Tensor draft_tokens_device = draft_tokens_device_.CreateView({num_nodes}, dtype_i32_);
225	
226	    // Copy draft tokens to GPU
227	    int* p_draft_tokens_host = static_cast<int*>(draft_tokens_host->data);
228	    for (int i = 0; i < num_sequence; i++) {
229	      const std::vector<SampleResult>& draft_output_tokens_i = draft_output_tokens[i];
230	      int start = cum_verify_lengths[i];
231	      int end = cum_verify_lengths[i + 1];
232	      // start/end is the range of the sequence i in probs_on_device, which includes the prob dist
233	      // of the draft tokens and the last committed token
234	      TVM_FFI_ICHECK_EQ(draft_output_tokens_i.size() + 1, end - start);
235	      for (int j = 0; j < end - start - 1; j++) {
236	        // Copy sampled token id
237	        p_draft_tokens_host[start + j + 1] = draft_output_tokens_i[j].GetTokenId();
238	      }
239	    }
240	    CopyArray(draft_tokens_host, draft_tokens_device, copy_stream_);
241	
242	    Tensor token_tree_first_child_host =
243	        token_tree_first_child_host_.CreateView({num_nodes}, dtype_i32_);
244	    Tensor token_tree_first_child_device =
245	        token_tree_first_child_device_.CreateView({num_nodes}, dtype_i32_);
246	    Tensor token_tree_next_sibling_host =
247	        token_tree_next_sibling_host_.CreateView({num_nodes}, dtype_i32_);
248	    Tensor token_tree_next_sibling_device =
249	        token_tree_next_sibling_device_.CreateView({num_nodes}, dtype_i32_);
250	    Tensor token_tree_parent_ptr_host =
251	        token_tree_parent_ptr_host_.CreateView({num_sequence}, dtype_i32_);
252	    Tensor token_tree_parent_ptr_device =
253	        token_tree_parent_ptr_device_.CreateView({num_sequence}, dtype_i32_);
254	    std::vector<int> token_tree_child_to_parent(/*n=*/num_nodes);
255	
256	    int* token_tree_first_child_ptr_host = static_cast<int*>(token_tree_first_child_host->data);
257	    int* token_tree_next_sibling_ptr_host = static_cast<int*>(token_tree_next_sibling_host->data);
258	    // Build the tree structure on CPU
259	    for (int i = 0; i < num_sequence; i++) {
260	      // Assuming no tree structure for now
261	      int start = cum_verify_lengths[i];
262	      int end = cum_verify_lengths[i + 1];
263	      TVM_FFI_ICHECK_GE(end - start, 2);
264	      for (int j = 0; j < end - start; j++) {
265	        int cur_node = j + start;
266	        int parent_node =
267	            token_tree_parent_ptr[cur_node] != -1 ? token_tree_parent_ptr[cur_node] + start : -1;
268	        token_tree_first_child_ptr_host[cur_node] = -1;
269	        if (parent_node != -1 && token_tree_first_child_ptr_host[parent_node] == -1) {
270	          token_tree_first_child_ptr_host[parent_node] = cur_node;
271	        }
272	        token_tree_child_to_parent[cur_node] = parent_node;
273	        if (cur_node + 1 < end && token_tree_parent_ptr[cur_node - start + 1] ==
274	                                      token_tree_parent_ptr[cur_node - start]) {
275	          token_tree_next_sibling_ptr_host[cur_node] = cur_node + 1;
276	        } else {
277	          token_tree_next_sibling_ptr_host[cur_node] = -1;
278	        }
279	      }
280	      static_cast<int*>(token_tree_parent_ptr_host->data)[i] = start;  // point to the root
281	    }
282	    // Copy token tree structure to GPU
283	    CopyArray(token_tree_first_child_host, token_tree_first_child_device, copy_stream_);
284	    CopyArray(token_tree_next_sibling_host, token_tree_next_sibling_device, copy_stream_);
285	    CopyArray(token_tree_parent_ptr_host, token_tree_parent_ptr_device, copy_stream_);
286	
287	    SyncCopyStream(device_, compute_stream_, copy_stream_);
288	
289	    gpu_verify_draft_tokens_func_(draft_probs_on_device, draft_tokens_device, probs_on_device,
290	                                  token_tree_first_child_device, token_tree_next_sibling_device,
291	                                  uniform_samples_device, token_tree_parent_ptr_device);
292	
293	    DeviceAPI::Get(device_)->SyncStreamFromTo(device_, compute_stream_, copy_stream_);
294	    CopyArray(token_tree_parent_ptr_device, token_tree_parent_ptr_host, copy_stream_);
295	
296	    std::vector<SampleResult> additional_sample_result;
297	    {
298	      additional_sample_result.reserve(num_sequence);
299	      // Sample one additional token for each sequence using the probablity at the last accepted
300	      // token.
301	      uniform_samples_device = GenerateUniformSamples(rngs, num_sequence);
302	      const Tensor& sample_indices_device = token_tree_parent_ptr_device;
303	      // Check need_prob_values
304	      bool need_prob_values = false;
305	      for (int i = 0; i < num_sequence; i++) {
306	        need_prob_values |= generation_cfg[i]->logprobs;
307	      }
308	      std::vector<int> top_prob_offset_indptr;
309	      if (!need_prob_values) {
310	        top_prob_offset_indptr.resize(num_sequence + 1, 0);
311	      } else {
312	        // Slow path: if any of the generation config requires prob values, we need to copy
313	        // sample_indices to host to compute top_prob_offset_indptr.
314	        DeviceAPI::Get(device_)->StreamSync(device_, copy_stream_);
315	        std::vector<int> sample_indices;
316	        sample_indices.reserve(num_sequence);
317	        const int* p_token_tree_parent_ptr = static_cast<int*>(token_tree_parent_ptr_host->data);
318	        for (int i = 0; i < num_sequence; i++) {
319	          sample_indices.push_back(p_token_tree_parent_ptr[i]);
320	        }
321	        CheckProbValues(generation_cfg, sample_indices, num_nodes, num_sequence, vocab_size_,
322	                        &top_prob_offset_indptr);
323	      }
324	      auto device_arrays =
325	          SampleOnGPU(probs_on_device, uniform_samples_device, sample_indices_device,
326	                      /*need_top_p=*/false, need_prob_values, num_nodes, top_prob_offset_indptr);
327	      auto host_arrays = CopyArraysToCPU(device_arrays, num_sequence, need_prob_values,
328	                                         top_prob_offset_indptr.back());
329	      additional_sample_result =
330	          CollectSampleResult(host_arrays, num_sequence, need_prob_values, top_prob_offset_indptr);
331	    }
332	
333	    std::vector<int> last_accepted_tree_node;
334	    last_accepted_tree_node.reserve(num_sequence);
335	    for (int i = 0; i < num_sequence; i++) {
336	      int start = cum_verify_lengths[i];
337	      int end = cum_verify_lengths[i + 1];
338	      int last_accepted = static_cast<int*>(token_tree_parent_ptr_host->data)[i];
339	      last_accepted_tree_node.push_back(last_accepted - start);
340	      int num_accepted = 0;
341	      for (int cur_node = last_accepted; cur_node != start;
342	           cur_node = token_tree_child_to_parent[cur_node]) {
343	        sample_results[i].push_back(draft_output_tokens[i][cur_node - start - 1]);
344	        num_accepted++;
345	      }
346	      std::reverse(sample_results[i].rbegin(), sample_results[i].rbegin() + num_accepted);
347	    }
348	
349	    // Append the additional sample result to the sample_results
350	    TVM_FFI_ICHECK_EQ(additional_sample_result.size(), num_sequence);
351	    for (int i = 0; i < num_sequence; i++) {
352	      sample_results[i].push_back(additional_sample_result[i]);
353	    }
354	
355	    RECORD_EVENT(trace_recorder_, request_ids, "finish draft verification");
356	    return {sample_results, last_accepted_tree_node};
357	  }
358	
359	 private:
360	  std::vector<SampleResult> BatchSampleTokensImpl(Tensor probs_on_device,                         //
361	                                                  const std::vector<int>& sample_indices,         //
362	                                                  const Array<String>& request_ids,               //
363	                                                  const Array<GenerationConfig>& generation_cfg,  //
364	                                                  const std::vector<RandomGenerator*>& rngs,      //
365	                                                  bool top_p_applied) {
366	    // probs_on_device: (n, v)
367	    RECORD_EVENT(trace_recorder_, request_ids, "start sampling");
368	    TVM_FFI_ICHECK_EQ(probs_on_device->ndim, 2);
369	    TVM_FFI_ICHECK_EQ(probs_on_device->device.device_id, device_.device_id);
370	    TVM_FFI_ICHECK_EQ(probs_on_device->device.device_type, device_.device_type);
371	    int num_samples = sample_indices.size();
372	    int num_probs = probs_on_device->shape[0];
373	    int vocab_size = probs_on_device->shape[1];
374	    if (num_samples == 0) {
375	      // This synchronization is necessary for making sure that this round
376	      // of model forward is finished.
377	      DeviceAPI::Get(device_)->StreamSync(device_, compute_stream_);
378	      return {};
379	    }
380	    TVM_FFI_ICHECK_EQ(request_ids.size(), num_samples);
381	    TVM_FFI_ICHECK_EQ(generation_cfg.size(), num_samples);
382	    TVM_FFI_ICHECK_EQ(rngs.size(), num_samples);
383	
384	    // Since `num_samples` may be larger than `max_num_sample_` in some cases,
385	    // we apply chunking to support large `num_samples`.
386	    std::vector<SampleResult> sample_results;
387	    if (num_samples <= max_num_sample_) {
388	      sample_results = ChunkSampleTokensImpl(probs_on_device, sample_indices, generation_cfg, rngs,
389	                                             top_p_applied);
390	    } else {
391	      for (int chunk_start = 0; chunk_start < num_samples; chunk_start += max_num_sample_) {
392	        int chunk_end = std::min(chunk_start + max_num_sample_, num_samples);
393	        std::vector<int> sample_indices_chunk(sample_indices.begin() + chunk_start,
394	                                              sample_indices.begin() + chunk_end);
395	        Array<GenerationConfig> generation_cfg_chunk(generation_cfg.begin() + chunk_start,
396	                                                     generation_cfg.begin() + chunk_end);
397	        std::vector<RandomGenerator*> rngs_chunk(rngs.begin() + chunk_start,
398	                                                 rngs.begin() + chunk_end);
399	        std::vector<SampleResult> sample_results_chunk = ChunkSampleTokensImpl(
400	            probs_on_device, sample_indices_chunk, generation_cfg_chunk, rngs_chunk, top_p_applied);
401	        sample_results.insert(sample_results.end(), sample_results_chunk.begin(),
402	                              sample_results_chunk.end());
403	      }
404	    }
405	
406	    RECORD_EVENT(trace_recorder_, request_ids, "finish sampling");
407	    return sample_results;
408	  }
409	
410	  /*! \brief Collect the sampling results from the computed Tensor results. */
411	  std::vector<SampleResult> CollectSampleResult(const std::vector<Tensor>& host_arrays,
412	                                                int num_samples, bool need_prob_values,
413	                                                const std::vector<int> top_prob_offset_indptr) {
414	    const int* p_sampled_token_ids = static_cast<const int*>(host_arrays[0]->data);
415	    const float* p_sampled_probs = nullptr;
416	    const float* p_top_prob_probs = nullptr;
417	    const int* p_top_prob_indices = nullptr;
418	    if (need_prob_values) {
419	      p_sampled_probs = static_cast<const float*>(host_arrays[1]->data);
420	      p_top_prob_probs = static_cast<const float*>(host_arrays[2]->data);
421	      p_top_prob_indices = static_cast<const int*>(host_arrays[3]->data);
422	    }
423	    std::vector<SampleResult> sample_results;
424	    sample_results.reserve(num_samples);
425	    TVM_FFI_ICHECK_EQ(top_prob_offset_indptr.size(), num_samples + 1);
426	    for (int i = 0; i < num_samples; ++i) {
427	      // Note: we set the probability in SampleResult to 1.0 since prob value is not needed.
428	      float sampled_prob = need_prob_values ? p_sampled_probs[i] : 1.0;
429	      std::vector<TokenProbPair> top_prob_tokens;
430	      top_prob_tokens.reserve(top_prob_offset_indptr[i + 1] - top_prob_offset_indptr[i]);
431	      for (int j = top_prob_offset_indptr[i]; j < top_prob_offset_indptr[i + 1]; ++j) {
432	        top_prob_tokens.emplace_back(p_top_prob_indices[j], p_top_prob_probs[j]);
433	      }
434	      sample_results.push_back(
435	          SampleResult{{p_sampled_token_ids[i], sampled_prob}, top_prob_tokens});
436	    }
437	    return sample_results;
438	  }
439	
440	  std::vector<SampleResult> ChunkSampleTokensImpl(Tensor probs_on_device,                         //
441	                                                  const std::vector<int>& sample_indices,         //
442	                                                  const Array<GenerationConfig>& generation_cfg,  //
443	                                                  const std::vector<RandomGenerator*>& rngs,      //
444	                                                  bool top_p_applied) {
445	    // probs_on_device: (n, v)
446	    int num_samples = sample_indices.size();
447	    int num_probs = probs_on_device->shape[0];
448	    int vocab_size = probs_on_device->shape[1];
449	
450	    // - Generate random numbers.
451	    //   Copy the random numbers and sample indices.
452	    auto uniform_samples_device = GenerateUniformSamples(rngs, num_samples);
453	    auto sample_indices_device = CopySampleIndicesToGPU(sample_indices);
454	
455	    // - Check if there is need for applying top p or prob values,
456	    //   so that argsort is needed.
457	    bool need_top_p = false;
458	    if (!top_p_applied) {
459	      need_top_p = CheckTopP(generation_cfg, sample_indices, num_probs, num_samples, vocab_size);
460	    }
461	    // The indptr array of the number of top probs for each sample.
462	    std::vector<int> top_prob_offset_indptr;
463	    bool need_prob_values = CheckProbValues(generation_cfg, sample_indices, num_probs, num_samples,
464	                                            vocab_size, &top_prob_offset_indptr);
465	
466	    // - Sample tokens on GPU, and take out the probability values if needed.
467	    std::vector<Tensor> device_arrays =
468	        SampleOnGPU(probs_on_device, uniform_samples_device, sample_indices_device, need_top_p,
469	                    need_prob_values, num_probs, top_prob_offset_indptr);
470	
471	    // - Copy the GPU sampling function results to CPU.
472	    std::vector<Tensor> host_arrays = CopyArraysToCPU(device_arrays, num_samples, need_prob_values,
473	                                                      top_prob_offset_indptr.back());
474	
475	    // - Collect the sampling results.
476	    return CollectSampleResult(host_arrays, num_samples, need_prob_values, top_prob_offset_indptr);
477	  }
