479	  /*! \brief Generate num_samples uniform random numbers, and copy them to GPU. */
480	  Tensor GenerateUniformSamples(const std::vector<RandomGenerator*>& rngs, int num_samples) {
481	    float* p_uniform_samples = static_cast<float*>(uniform_samples_host_->data);
482	    for (int i = 0; i < num_samples; ++i) {
483	      p_uniform_samples[i] = rngs[i]->GetRandomNumber();
484	    }
485	    Tensor uniform_samples_host = uniform_samples_host_.CreateView({num_samples}, dtype_f32_);
486	    Tensor uniform_samples_device = uniform_samples_device_.CreateView({num_samples}, dtype_f32_);
487	    CopyArray(/*src=*/uniform_samples_host, /*dst=*/uniform_samples_device, copy_stream_);
488	    return uniform_samples_device;
489	  }
490	
491	  /*! \brief Generate uniform random numbers, and copy the numbers and sample indices to GPU. The
492	   * number of samples for each random generator is given by `cum_num_samples`. */
493	  Tensor GenerateUniformSamples(const std::vector<RandomGenerator*>& rngs,
494	                                const std::vector<int>& cum_num_samples) {
495	    float* p_uniform_samples = static_cast<float*>(uniform_samples_host_->data);
496	    int total_samples = cum_num_samples.back();
497	    for (int i = 0; i + 1 < static_cast<int>(cum_num_samples.size()); ++i) {
498	      for (int j = cum_num_samples[i]; j < cum_num_samples[i + 1]; ++j) {
499	        p_uniform_samples[j] = rngs[i]->GetRandomNumber();
500	      }
501	    }
502	    Tensor uniform_samples_host = uniform_samples_host_.CreateView({total_samples}, dtype_f32_);
503	    Tensor uniform_samples_device = uniform_samples_device_.CreateView({total_samples}, dtype_f32_);
504	    CopyArray(/*src=*/uniform_samples_host, /*dst=*/uniform_samples_device, copy_stream_);
505	    return uniform_samples_device;
506	  }
507	
508	  /*! \brief Generate uniform random numbers, and copy the numbers and sample indices to GPU. */
509	  Tensor CopySampleIndicesToGPU(const std::vector<int>& sample_indices) {
510	    int* p_sample_indices = static_cast<int*>(sample_indices_host_->data);
511	    std::copy(sample_indices.begin(), sample_indices.end(), p_sample_indices);
512	    // Copy the sample indices to GPU.
513	    int num_samples = static_cast<int>(sample_indices.size());
514	    Tensor sample_indices_host = sample_indices_host_.CreateView({num_samples}, dtype_i32_);
515	    Tensor sample_indices_device = sample_indices_device_.CreateView({num_samples}, dtype_i32_);
516	    CopyArray(/*src=*/sample_indices_host, /*dst=*/sample_indices_device, copy_stream_);
517	    return sample_indices_device;
518	  }
519	
520	  /*! \brief Check if top p is needed. Update host top p array in place. */
521	  bool CheckTopP(const Array<GenerationConfig>& generation_cfg,
522	                 const std::vector<int>& sample_indices, int num_probs, int num_samples,
523	                 int vocab_size) {
524	    // Initialize top p values with -1.
525	    float* p_top_p = static_cast<float*>(top_p_host_->data);
526	    for (int i = 0; i < num_probs; ++i) {
527	      p_top_p[i] = -1.0;
528	    }
529	    bool need_top_p = false;
530	    for (int i = 0; i < num_samples; ++i) {
531	      if (p_top_p[sample_indices[i]] == -1.0) {
532	        p_top_p[sample_indices[i]] = generation_cfg[i]->top_p;
533	        need_top_p |= generation_cfg[i]->top_p != 1.0;
534	      } else {
535	        TVM_FFI_ICHECK(fabs(p_top_p[sample_indices[i]] - generation_cfg[i]->top_p) < eps_)
536	            << "GPU sampler requires the top_p values for each prob distribution are the same.";
537	      }
538	    }
539	    for (int i = 0; i < num_probs; ++i) {
540	      p_top_p[i] = std::max(p_top_p[i], eps_);
541	    }
542	    return need_top_p;
543	  }
544	
545	  /*! \brief Check whether prob values are needed, and collect info when necessary. */
546	  bool CheckProbValues(const Array<GenerationConfig>& generation_cfg,
547	                       const std::vector<int>& sample_indices, int num_probs, int num_samples,
548	                       int vocab_size, std::vector<int>* top_prob_offset_indptr) {
549	    top_prob_offset_indptr->reserve(num_samples + 1);
550	    top_prob_offset_indptr->push_back(0);
551	    int* p_top_prob_offsets = static_cast<int*>(top_prob_offsets_host_->data);
552	    int num_top_probs = 0;
553	    bool need_prob_values = false;
554	    for (int i = 0; i < num_samples; ++i) {
555	      need_prob_values |= generation_cfg[i]->logprobs;
556	      for (int j = 0; j < generation_cfg[i]->top_logprobs; ++j) {
557	        p_top_prob_offsets[num_top_probs++] = sample_indices[i] * vocab_size + j;
558	      }
559	      top_prob_offset_indptr->push_back(top_prob_offset_indptr->back() +
560	                                        generation_cfg[i]->top_logprobs);
561	    }
562	    TVM_FFI_ICHECK_EQ(num_top_probs, top_prob_offset_indptr->back());
563	    return need_prob_values;
564	  }
565	
566	  /*! \brief Sample tokens on GPU. Take out the probability values when needed. */
567	  std::vector<Tensor> SampleOnGPU(Tensor probs_on_device, Tensor uniform_samples_device,
568	                                  Tensor sample_indices_device,  //
569	                                  bool need_top_p, bool need_prob_values, int num_probs,
570	                                  const std::vector<int>& top_prob_offset_indptr) {
571	    Tensor sampled_token_ids_device{nullptr};
572	    Tensor sampled_probs_device{nullptr};
573	    Tensor top_prob_probs_device{nullptr};
574	    Tensor top_prob_indices_device{nullptr};
575	
576	    if (!need_top_p && !need_prob_values) {
577	      // - Short path: If top_p and prob values are not needed, we directly sample from multinomial.
578	      SyncCopyStream(device_, compute_stream_, copy_stream_);
579	      if (flashinfer_sampling_available_) {
580	        sampled_token_ids_device =
581	            sampled_token_ids_device_.CreateView({sample_indices_device->shape[0]}, dtype_i32_);
582	        flashinfer_multinomial_sample_func_.value()(probs_on_device, uniform_samples_device,
583	                                                    sample_indices_device,
584	                                                    sampled_token_ids_device);
585	      } else {
586	        sampled_token_ids_device =
587	            gpu_multinomial_from_uniform_func_(probs_on_device, uniform_samples_device,
588	                                               sample_indices_device)
589	                .cast<Tensor>();
590	      }
591	      return {sampled_token_ids_device, sampled_probs_device, top_prob_probs_device,
592	              top_prob_indices_device};
593	    }
594	
595	    // - Argsort the probability.
596	    Array<Tensor> argsort_results = gpu_argsort_probs_func_(probs_on_device).cast<Array<Tensor>>();
597	    TVM_FFI_ICHECK_EQ(argsort_results.size(), 2);
598	    Tensor sorted_probs_on_device = argsort_results[0];
599	    Tensor sorted_indices_on_device = argsort_results[1];
600	
601	    // - Copy auxiliary array for top-p and prob values in ahead.
602	    Tensor top_p_device;
603	    Tensor top_prob_offsets_device;
604	    if (need_top_p) {
605	      Tensor top_p_host = top_p_host_.CreateView({num_probs}, dtype_f32_);
606	      top_p_device = top_p_device_.CreateView({num_probs}, dtype_f32_);
607	      CopyArray(/*src=*/top_p_host, /*dst=*/top_p_device, copy_stream_);
608	    }
609	    if (need_prob_values) {
610	      int num_top_probs = top_prob_offset_indptr.back();
611	      Tensor top_prob_offsets_host = top_prob_offsets_host_.CreateView({num_top_probs}, dtype_i32_);
612	      top_prob_offsets_device = top_prob_offsets_device_.CreateView({num_top_probs}, dtype_i32_);
613	      CopyArray(/*src=*/top_prob_offsets_host, /*dst=*/top_prob_offsets_device, copy_stream_);
614	    }
615	    SyncCopyStream(device_, compute_stream_, copy_stream_);
616	
617	    if (need_top_p) {
618	      // - Sample with top_p applied.
619	      sampled_token_ids_device =
620	          gpu_sample_with_top_p_func_(sorted_probs_on_device, sorted_indices_on_device,
621	                                      uniform_samples_device, sample_indices_device, top_p_device)
622	              .cast<Tensor>();
623	    } else {
624	      // - Sample without top_p.
625	      if (flashinfer_sampling_available_) {
626	        sampled_token_ids_device =
627	            sampled_token_ids_device_.CreateView({sample_indices_device->shape[0]}, dtype_i32_);
628	        flashinfer_multinomial_sample_func_
629	            .value()(probs_on_device, uniform_samples_device, sample_indices_device,
630	                     sampled_token_ids_device)
631	            .cast<Tensor>();
632	      } else {
633	        sampled_token_ids_device =
634	            gpu_multinomial_from_uniform_func_(probs_on_device, uniform_samples_device,
635	                                               sample_indices_device)
636	                .cast<Tensor>();
637	      }
638	    }
639	
640	    if (need_prob_values) {
641	      // - Take the probability values.
642	      Array<Tensor> prob_value_results =
643	          gpu_sampler_take_probs_func_(probs_on_device, sorted_indices_on_device,
644	                                       sample_indices_device, sampled_token_ids_device,
645	                                       top_prob_offsets_device)
646	              .cast<Array<Tensor>>();
647	      sampled_probs_device = prob_value_results[0];
648	      top_prob_probs_device = prob_value_results[1];
649	      top_prob_indices_device = prob_value_results[2];
650	    }
651	
652	    return {sampled_token_ids_device, sampled_probs_device, top_prob_probs_device,
653	            top_prob_indices_device};
654	  }
655	
656	  /*! \brief Copy the results of GPU sampling functions back to CPU. */
657	  std::vector<Tensor> CopyArraysToCPU(const std::vector<Tensor>& device_arrays,  //
658	                                      int num_samples, bool need_prob_values, int num_top_probs) {
659	    Tensor sampled_token_ids_device = device_arrays[0];
660	    Tensor sampled_probs_device = device_arrays[1];
661	    Tensor top_prob_probs_device = device_arrays[2];
662	    Tensor top_prob_indices_device = device_arrays[3];
663	    TVM_FFI_ICHECK(sampled_token_ids_device.defined());
664	    TVM_FFI_ICHECK_EQ(sampled_token_ids_device->ndim, 1);
665	    TVM_FFI_ICHECK_EQ(sampled_token_ids_device->shape[0], num_samples);
666	    Tensor sampled_token_ids_host = sampled_token_ids_host_.CreateView({num_samples}, dtype_i32_);
667	    CopyArray(/*src=*/sampled_token_ids_device, /*dst=*/sampled_token_ids_host, compute_stream_);
668	
669	    Tensor sampled_probs_host{nullptr};
670	    Tensor top_prob_probs_host{nullptr};
671	    Tensor top_prob_indices_host{nullptr};
672	    if (need_prob_values) {
673	      TVM_FFI_ICHECK(sampled_probs_device.defined());
674	      TVM_FFI_ICHECK(top_prob_probs_device.defined());
675	      TVM_FFI_ICHECK(top_prob_indices_device.defined());
676	      TVM_FFI_ICHECK_EQ(sampled_probs_device->ndim, 1);
677	      TVM_FFI_ICHECK_EQ(top_prob_probs_device->ndim, 1);
678	      TVM_FFI_ICHECK_EQ(top_prob_indices_device->ndim, 1);
679	      TVM_FFI_ICHECK_EQ(sampled_probs_device->shape[0], num_samples);
680	      TVM_FFI_ICHECK_EQ(top_prob_probs_device->shape[0], num_top_probs);
681	      TVM_FFI_ICHECK_EQ(top_prob_indices_device->shape[0], num_top_probs);
682	      sampled_probs_host = sampled_probs_host_.CreateView({num_samples}, dtype_i32_);
683	      top_prob_probs_host = top_prob_probs_host_.CreateView({num_top_probs}, dtype_f32_);
684	      top_prob_indices_host = top_prob_indices_host_.CreateView({num_top_probs}, dtype_i32_);
685	      CopyArray(/*src=*/sampled_probs_device, /*dst=*/sampled_probs_host, compute_stream_);
686	      if (num_top_probs > 0) {
687	        CopyArray(/*src=*/top_prob_probs_device, /*dst=*/top_prob_probs_host, compute_stream_);
688	        CopyArray(/*src=*/top_prob_indices_device, /*dst=*/top_prob_indices_host, compute_stream_);
689	      }
690	    }
691	
692	    // Synchronize for CPU to get the correct array results.
693	    DeviceAPI::Get(device_)->StreamSync(device_, compute_stream_);
694	
695	    return {sampled_token_ids_host, sampled_probs_host, top_prob_probs_host, top_prob_indices_host};
696	  }
697	
698	  // Model configurations
699	  const int max_num_sample_;
700	  const int vocab_size_;
701	  const DLDataType dtype_i32_ = DLDataType{kDLInt, 32, 1};
702	  const DLDataType dtype_f32_ = DLDataType{kDLFloat, 32, 1};
703	  const bool flashinfer_sampling_available_;
704	  // Functions for sampling on GPU.
705	  Device device_;
706	  Function gpu_multinomial_from_uniform_func_;
707	  Function gpu_argsort_probs_func_;
708	  Function gpu_sample_with_top_p_func_;
709	  Function gpu_sampler_take_probs_func_;
710	  Function gpu_verify_draft_tokens_func_;
711	  Function gpu_renormalize_by_top_p_func_;
712	  Optional<Function> flashinfer_multinomial_sample_func_;
713	  // Auxiliary Tensors on CPU
714	  Tensor uniform_samples_host_;
715	  Tensor sample_indices_host_;
716	  Tensor top_p_host_;
717	  Tensor top_p_init_pivots_host_;
718	  Tensor top_prob_offsets_host_;
719	  Tensor draft_tokens_host_;
720	  Tensor token_tree_first_child_host_;
721	  Tensor token_tree_next_sibling_host_;
722	  Tensor token_tree_parent_ptr_host_;
723	  Tensor sampled_token_ids_host_;
724	  Tensor sampled_probs_host_;
725	  Tensor top_prob_probs_host_;
726	  Tensor top_prob_indices_host_;
727	  // Auxiliary Tensors on GPU
728	  Tensor uniform_samples_device_;
729	  Tensor sample_indices_device_;
730	  Tensor top_p_device_;
731	  Tensor top_p_init_pivots_device_;
732	  Tensor top_prob_offsets_device_;
733	  Tensor draft_tokens_device_;
734	  Tensor token_tree_first_child_device_;
735	  Tensor token_tree_next_sibling_device_;
736	  Tensor token_tree_parent_ptr_device_;
737	  Tensor sampled_token_ids_device_;
738	  // The event trace recorder for requests. */
739	  Optional<EventTraceRecorder> trace_recorder_;
740	  // The device stream for the default computation operations.
741	  TVMStreamHandle compute_stream_ = nullptr;
742	  // The device stream for copying auxiliary data structure to GPU.
743	  TVMStreamHandle copy_stream_ = nullptr;
744	  const float eps_ = 1e-5;
745	  const int num_top_p_cutoff_pivots_ = 3;
746	};
747	
748	Sampler Sampler::CreateGPUSampler(int max_num_sample, int vocab_size, FunctionTable* ft,
749	                                  DLDevice device, Optional<EventTraceRecorder> trace_recorder) {
750	  return Sampler(tvm::ffi::make_object<GPUSampler>(max_num_sample, vocab_size, ft, device,
751	                                                   std::move(trace_recorder)));
752	}
753	
754	}  // namespace serve
755	}  // namespace llm
756	}  // namespace mlc
